script:
frappe.ui.form.on("Sales Order", {
    after_save: function(frm) {
        var isLayby = window.location.search.indexOf("layby=1") > -1;
        if (!isLayby) return;

        var grand_total = frm.doc.grand_total || 0;
        var items = frm.doc.items || [];
        var lines = [
            "=============================",
            "         LAYBY RECEIPT       ",
            "=============================",
            "Order     : " + frm.doc.name,
            "Date      : " + frm.doc.transaction_date,
            "Customer  : " + (frm.doc.customer_name || frm.doc.customer || "Walk-in"),
            "-----------------------------",
            "ITEMS:",
        ];
        items.forEach(function(i) {
            lines.push("  " + i.item_name + " x" + i.qty + "  @  " + i.rate + "  =  " + i.amount);
        });
        lines = lines.concat([
            "-----------------------------",
            "TOTAL     : " + frm.doc.currency + " " + grand_total,
            "=============================",
            "  Thank you for your Layby!  ",
            "  Please keep this receipt.  ",
            "=============================",
        ]);

        var blob = new Blob([lines.join("\n")], { type: "text/plain" });
        var url = URL.createObjectURL(blob);
        var a = document.createElement("a");
        a.href = url;
        a.download = "Layby-" + frm.doc.name + ".txt";
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);

        frappe.show_alert({ message: "Layby receipt downloaded! Closing...", indicator: "green" }, 3);
        setTimeout(function() { window.close(); }, 2500);
    }
});
